// File type detection and text extraction routing
const runId = $('WF02 Trigger').first().json.runId;
const fileName = $('WF02 Trigger').first().json.inputFile.name || '';
const ext = fileName.split('.').pop()?.toLowerCase();

console.log(`[WF02][${runId}] Processing file: ${fileName} (type: ${ext})`);

// Supported types: pdf, docx, txt, md
const supportedTypes = ['pdf', 'docx', 'doc', 'txt', 'md', 'markdown'];
if (!supportedTypes.includes(ext)) {
  throw new Error(`Unsupported file type: .${ext}. Supported: ${supportedTypes.join(', ')}`);
}

// In production this calls SUB_Parse_Document_By_Type
// For now, pass through with file type metadata
return [{
  json: {
    runId,
    fileName,
    fileType: ext,
    mimeType: $('WF02 Trigger').first().json.inputFile.mimeType,
    fileUrl: $('WF02 Trigger').first().json.inputFile.url,
    sampleFiles: $('WF02 Trigger').first().json.sampleFiles || [],
    options: $('WF02 Trigger').first().json.options || {}
  }
}];

// Build list of sample parse tasks
const samples = $('Detect File Type & Extract Text').first().json.sampleFiles || [];
const runId = $('Detect File Type & Extract Text').first().json.runId;

if (samples.length === 0) {
  console.log(`[WF02][${runId}] No samples to parse`);
  return [{ json: { runId, parsedSamples: [] } }];
}

// Return items for each sample to be parsed
return samples.map(s => ({
  json: {
    runId,
    sampleId: s.fileId,
    fileName: s.name,
    fileUrl: s.url,
    fileType: s.name.split('.').pop()?.toLowerCase() || 'pdf'
  }
}));

const runId = $('Detect File Type & Extract Text').first().json.runId;
const sourceResult = $('Call Parse Sub-Workflow').first().json;
const sampleResults = $items('Parse Each Sample').map(i => i.json);

const artifact = {
  runId,
  source: {
    plainText: sourceResult.plainText || '',
    sections: sourceResult.sections || [],
    metadata: sourceResult.metadata || { pageCount: 0, wordCount: 0, hasTables: false }
  },
  samples: sampleResults.map(s => ({
    sampleId: s.sampleId || s.fileId,
    plainText: s.plainText || '',
    sections: s.sections || []
  })),
  parsedAt: new Date().toISOString()
};

console.log(`[WF02][${runId}] Normalized artifact built. Source words: ${artifact.source.metadata.wordCount}, Samples: ${artifact.samples.length}`);

return [{ json: artifact }];
